use std::fs::write;
use std::io::{self, BufReader, Result};

struct LogEntry {
    source_file: String,
    line_content: String,
    timestamp: String,
}

fn process_log_stream(paths: &[&str]) -> io::Result<Vec<LogEntry>> {
    let mut entries = Vec::new();
    for path in paths {
        println!("Processing file: {}", path);
        let file = std::fs::File::open(path)?;
        let reader = BufReader::new(file);
        for line_result in io::BufRead::lines(reader) {
            let line = match line_result {
                Ok(l) => l,
                Err(e) => { 
                    eprintln!("Error reading line from {}: {}", path, e);
                    continue;
                }
            };
            if !line.is_empty() {
                let entry = LogEntry {
                    source_file: path.to_string(),
                    line_content: line,
                    timestamp: "2024-01-01T00:00:00Z".to_string(),
                };
                entries.push(entry);
            }
        }
    }
    Ok(entries)
}

fn main() -> io::Result<()> {
    let log_paths = &["test1.log", "test2.log"];
    for path in log_paths.iter() {
        if !std::path::Path::new(path).exists() {
            println!("Creating dummy file: {}", path);
            write(path, "Some test line 1nAnother entry for n")?;
        }
    }

    match process_log_stream(log_paths) {
        Ok(entries) => {
            println!("Successfully aggregated {} log entries.", entries.len());
        },
        Err(e) => eprintln!("An overall error occurred: {}", e),
    }
    Ok(())
}

use std::io::{self, Write};
use std::collections::VecDeque;

#[derive(Debug)]
struct Command {
    name: String,
    args: Vec<String>,
}

impl From<&str> for Command {
    fn from(s: &str) -> Self {
        let parts: Vec<&str> = s.split_whitespace().collect();
        if parts.is_empty() {
            return Command { name: String::new(), args: Vec::new() };
        }
        Command {
            name: parts[0].to_string(),
            args: parts.iter().skip(1).map(|&s| s.to_string()).collect(),
        }
    }
}

fn process_input(line: &str) -> Command {
    Command::from(line)
}

fn main() -> io::Result<()> {
    let mut buffer: VecDeque<String> = VecDeque::new();
    let mut stdin = io::stdin();

    println!("Enter commands (e.g., 'add 5 10') and hit enter.");

    loop {
        print!("> ");
        io::stdout().flush()?;

        let mut input_line = String::new();
        match io::stdin().read_line(&mut input_line) {
            Ok(0) => break,
            Ok(_) => {
                let trimmed = input_line.trim();
                if trimmed.is_empty() {
                    continue;
                }

                let command = process_input(trimmed);
                println!("Processing command: {:?}", command);

                buffer.push_back(format!("Processed {}", command.name));
            }
            Err(e) => {
                eprintln!("Error reading input: {}", e);
                break;
            }
        }
    }

    println!("
--- End of Session ---");
    if !buffer.is_empty() {
        let output_data: Vec<String> = buffer.iter().cloned().collect();
        let output_data = output_data.join("|");
        println!("Simulated serialized output: {}", output_data);
    }

    Ok(())
}

use std::collections::{HashMap, HashSet, VecDeque};
use std::fs::File;
use std::io::{self, BufReader, Read};
use std::path::Path;

struct Edge{
    source: u32,
    target: u32,
}

fn bfs_query(start_node: u32, adjacency_list: &HashMap<u32, Vec<u32>>) -> Vec<u32> {
    let mut queue: VecDeque<u32> = VecDeque::new();
    let mut visited: HashSet<u32> = HashSet::new();
    let mut result: Vec<u32> = Vec::new();

    queue.push_back(start_node);
    visited.insert(start_node);

    while let Some(current) = queue.pop_front() {
        result.push(current);

        if let Some(neighbors) = adjacency_list.get(&current) {
            for &neighbor in neighbors {
                if !visited.contains(&neighbor) {
                    visited.insert(neighbor);
                    queue.push_back(neighbor);
                }
            }
        }
    }
    result
}

fn main() -> io::Result<()> {
    let file_path = "graph_data.bin";
    let start_node: u32 = 1;

    if !Path::new(file_path).exists() {
        println!("Please create a dummy binary file named graph_data.bin to test this.");
        return Ok(())
    }

    let file = File::open(file_path)?;
    let mut reader = BufReader::new(file);
    let mut buffer = [0u8; 1024];
    reader.read(&mut buffer)?;

    let mut adj: HashMap<u32, Vec<u32>> = HashMap::new();

    for i in 0..buffer.len() / 8 {
        let offset = i * 8;
        if buffer[offset] == 0 && offset > 0 { break; }

        let source: u32 = u32::from_le_bytes(buffer[offset..offset+4].try_into().unwrap());
        let target: u32 = u32::from_le_bytes(buffer[offset+4..offset+8].try_into().unwrap());

        adj.entry(source).or_insert_with(Vec::new).push(target);
    }

    let reachable_nodes = bfs_query(start_node, &adj);
    println!("Reachable nodes from {}: {:?}", start_node, reachable_nodes);

    Ok(())
}

