struct BlogPost {
    title: String,
    body_content: Vec<u8>,
    author_id: u64,
}

fn process_posts(posts: &Vec<BlogPost>) -> Result<(), Box<dyn std::error::Error>> {
    for post in posts.iter() {
        println!("Processing post title: {}", post.title);
        if post.body_content.is_empty() {
            return Err(format!("Body content missing for author {}", post.author_id).into());
        }
    }
    Ok(())
}

